import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";
import BreathingExercise from "../components/BreathingExercise";

import { isCrisisMessage } from "../utils/crisisEngine";
import { crisisReply } from "../utils/aiReplies";
import { analyzeMood, saveMood } from "../utils/moodEngine";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [showBreathing, setShowBreathing] = useState(false);

  const chatEndRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "ai",
        text: "Hi  I'm your AI mental health assistant. How are you feeling today?",
      },
    ]);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const getAIReply = (mood) => {
    const replies = {
      happy: "That's wonderful  What made you feel happy?",
      sad: "I'm really sorry  Want to share what's bothering you?",
      angry: "That sounds frustrating  Let's slow down together.",
      anxious: "That can be overwhelming  Want to try a short breathing exercise?",
      calm: "It's good to feel balanced  Keep that peace going!",
      neutral: "I'm listening  Tell me more about what's on your mind."
    };

    return replies[mood] || "I'm listening  Tell me more about what's on your mind.";
  };

  const handleSend = async () => {
    if (!input.trim()) return;

    const userText = input;

    setMessages((prev) => [...prev, { sender: "user", text: userText }]);
    setInput("");

    //  CRISIS DETECTION
    if (isCrisisMessage(userText)) {
      setMessages((prev) => [
        ...prev,
        { sender: "ai", text: crisisReply() },
      ]);

      //  SILENT EMERGENCY ALERT
      try {
        await fetch("http://localhost:5000/api/emergency/alert", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            altNumber: localStorage.getItem("altPhone"),
            message: userText,
          }),
        });
      } catch (err) {
        console.error("Emergency alert failed", err);
      }

      setShowBreathing(true);
      return;
    }

    //  NORMAL CHAT FLOW - Use the mood engine
    const moodData = analyzeMood(userText);
    saveMood(moodData);

    setTimeout(() => {
      setMessages((prev) => [
        ...prev,
        { sender: "ai", text: getAIReply(moodData.mood) },
      ]);
    }, 600);
  };

  return (
    <div className="chat-page">
      <div className="chat-card">
        <div className="chat-header">
          <span></span>
          <h2>General Chat</h2>
        </div>

        <div className="chat-body">
          {messages.map((msg, i) => (
            <div key={i} className={`chat-bubble ${msg.sender}`}>
              {msg.text}
            </div>
          ))}

          {showBreathing && <BreathingExercise />}
          <div ref={chatEndRef} />
        </div>

        <div className="chat-input">
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Type how you feel..."
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>
      </div>
    </div>
  );
};

export default GeneralChat;
